'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { signInWithEmailAndPassword, GoogleAuthProvider, signInWithPopup } from 'firebase/auth';
import { auth } from '@/lib/firebase/config';
import { Loader2, Check } from 'lucide-react';
import Link from 'next/link';

export default function LoginPage() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const router = useRouter();

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    
    try {
      await signInWithEmailAndPassword(auth, email, password);
      router.push('/dashboard');
    } catch (err: any) {
      setError(err.message || 'Failed to login');
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleLogin = async () => {
    setLoading(true);
    setError('');
    
    try {
      const provider = new GoogleAuthProvider();
      await signInWithPopup(auth, provider);
      router.push('/dashboard');
    } catch (err: unknown) {
      setError((err as Error).message || 'Failed to login with Google');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex min-h-screen bg-white text-slate-900 font-sans">
      
      {/* Left Dark Panel */}
      <div className="hidden lg:flex lg:w-[45%] bg-[#0a0a0a] text-white p-12 flex-col relative overflow-hidden">
        {/* Logo */}
        <div className="flex items-center gap-2 mb-20 relative z-10">
          <div className="w-8 h-8 rounded-lg bg-[#00ea77] flex items-center justify-center">
            <div className="w-3 h-3 bg-black rounded-sm"></div>
          </div>
          <span className="font-bold text-xl tracking-tight">KhataX</span>
        </div>

        <div className="relative z-10 max-w-lg">
          <h1 className="text-5xl font-bold tracking-tight mb-6 leading-[1.1]">
            Empower your <br />
            business with <br />
            <span className="text-[#00ea77]">AI-first</span> <br />
            accounting.
          </h1>
          <p className="text-slate-400 text-lg mb-12 max-w-md">
            Automate your invoicing and expense tracking with our intelligent premium platform.
          </p>

          {/* Glowing element */}
          <div className="absolute top-[80%] left-[-10%] w-72 h-72 bg-[#00ea77]/20 rounded-full blur-[80px] pointer-events-none"></div>

          {/* Invoice Mockup Card */}
          <div className="bg-[#111]/80 backdrop-blur-sm border border-white/10 rounded-2xl p-6 shadow-2xl relative">
            <div className="flex justify-between items-start mb-6">
              <div>
                <p className="text-[10px] font-bold tracking-widest text-[#00ea77] uppercase mb-1">INVOICE #8842</p>
                <h3 className="text-white font-bold text-lg">Design Agency Co.</h3>
              </div>
              <span className="text-xs font-bold text-[#00ea77] bg-[#00ea77]/10 px-3 py-1 rounded-full border border-[#00ea77]/20">PAID</span>
            </div>
            <div className="w-3/4 h-2 bg-white/5 rounded-full mb-3"></div>
            <div className="w-1/2 h-2 bg-white/5 rounded-full mb-8"></div>
            <div className="flex justify-between items-end">
              <span className="text-sm text-slate-500 font-medium tracking-wide">Total Amount</span>
              <span className="text-3xl font-bold text-white">$4,250.00</span>
            </div>
          </div>
        </div>

        <div className="mt-auto relative z-10 pt-12">
           <p className="text-slate-500 text-sm italic">&quot;The most intuitive financial platform we&apos;ve ever used.&quot; — CEO, TechFlow</p>
        </div>
      </div>

      {/* Right Light Panel */}
      <div className="flex-1 flex flex-col items-center justify-center p-6 lg:p-12 relative">
        <div className="w-full max-w-[440px]">
          
          {/* Top Toggle */}
          <div className="flex bg-slate-100 p-1 rounded-lg mb-12">
            <button className="flex-1 py-2 text-sm font-semibold bg-white text-slate-900 rounded shadow-sm">
              Login
            </button>
            <Link href="/signup" className="flex-1 py-2 text-sm font-semibold text-slate-500 text-center hover:text-slate-900 transition">
              Sign Up
            </Link>
          </div>

          <div className="mb-8">
            <h2 className="text-3xl font-bold tracking-tight text-slate-900 mb-2">Welcome back</h2>
            <p className="text-slate-500">Please enter your details to sign in.</p>
          </div>

          <button 
            type="button"
            onClick={handleGoogleLogin}
            disabled={loading}
            className="w-full flex items-center justify-center gap-3 py-3 px-4 border border-slate-200 rounded-lg hover:bg-slate-50 transition font-medium text-slate-700 mb-6 group disabled:opacity-50"
          >
            <svg viewBox="0 0 24 24" width="20" height="20" xmlns="http://www.w3.org/2000/svg">
              <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
              <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
              <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
              <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
            </svg>
            Continue with Google
          </button>

          <div className="flex items-center gap-4 mb-6">
            <div className="flex-1 border-t border-slate-200"></div>
            <span className="text-xs font-bold text-slate-400 tracking-wider">OR SIGN IN WITH EMAIL</span>
            <div className="flex-1 border-t border-slate-200"></div>
          </div>

          <form onSubmit={handleLogin} className="space-y-5">
            {error && (
              <div className="bg-red-50 text-red-600 p-3 rounded-md text-sm font-medium border border-red-100">
                {error}
              </div>
            )}
            
            <div className="space-y-1.5">
              <label className="text-xs font-bold tracking-wide text-slate-500 uppercase" htmlFor="email">Business Email</label>
              <input 
                id="email"
                type="email" 
                required
                className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#00ea77] focus:border-transparent transition-colors placeholder:text-slate-400"
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                placeholder="name@company.com"
              />
            </div>
            
            <div className="space-y-1.5">
              <div className="flex items-center justify-between">
                <label className="text-xs font-bold tracking-wide text-slate-500 uppercase" htmlFor="password">Password</label>
                <Link href="#" className="text-xs font-bold text-[#00ea77] hover:text-[#00c563]">Forgot Password?</Link>
              </div>
              <input 
                id="password"
                type="password" 
                required
                className="w-full px-4 py-3 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-[#00ea77] focus:border-transparent transition-colors placeholder:text-slate-400"
                value={password}
                onChange={(e) => setPassword(e.target.value)}
                placeholder="••••••••"
              />
            </div>
            
            <div className="flex items-center mb-6 pt-2">
              <div className="flex items-center h-5">
                <div className="relative flex items-center justify-center w-5 h-5">
                  <input
                    id="remember"
                    type="checkbox"
                    className="appearance-none w-5 h-5 border border-slate-300 rounded checked:bg-[#00ea77] checked:border-[#00ea77] transition-colors cursor-pointer"
                  />
                  <Check className="w-3 h-3 text-black absolute pointer-events-none opacity-0 data-[checked=true]:opacity-100" />
                </div>
              </div>
              <div className="ml-3">
                <label htmlFor="remember" className="text-sm font-medium text-slate-600 cursor-pointer">
                  Keep me signed in
                </label>
              </div>
            </div>

            <button 
              type="submit" 
              disabled={loading}
              className="w-full flex justify-center items-center py-3.5 px-4 rounded-lg text-sm font-bold text-black bg-[#00ea77] hover:bg-[#00c563] focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-[#00ea77] disabled:opacity-50 transition-colors shadow-lg shadow-[#00ea77]/20 uppercase tracking-widest gap-2"
            >
              {loading ? <Loader2 className="h-5 w-5 animate-spin" /> : 'Sign In'}
              {!loading && <span className="text-lg leading-none">→</span>}
            </button>
          </form>

          <p className="mt-8 text-center text-sm text-slate-500 font-medium">
            New to the platform? <Link href="/signup" className="text-slate-900 border-b border-black font-bold pb-0.5 hover:text-[#00ea77] hover:border-[#00ea77] transition-colors">Create an account</Link>
          </p>

        </div>

        <div className="absolute bottom-8 flex gap-6 text-xs font-semibold text-slate-400">
          <Link href="#" className="hover:text-slate-600">Privacy Policy</Link>
          <Link href="#" className="hover:text-slate-600">Terms of Service</Link>
          <Link href="#" className="hover:text-slate-600">Contact Support</Link>
        </div>
      </div>
    </div>
  );
}

'use client';

import { useState } from 'react';
import { useMasterDataStore } from '@/store/useMasterDataStore';
import { Item } from '@/types';
import { Plus, Search, Edit, Trash2, X, AlertTriangle } from 'lucide-react';
import { useForm } from 'react-hook-form';

export default function InventoryPage() {
  const { items, isLoading, addItem, updateItem, deleteItem } = useMasterDataStore();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingItem, setEditingItem] = useState<Item | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  const { register, handleSubmit, reset, watch } = useForm<Omit<Item, 'id' | 'currentStock'>>();
  
  const itemType = watch('type', 'product');

  const filteredItems = items.filter(i => 
    i.name.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const openAddModal = () => {
    setEditingItem(null);
    reset({
      type: 'product',
      name: '',
      description: '',
      unit: 'PCS',
      purchasePrice: 0,
      salePrice: 0,
      taxRate: 18,
      openingStock: 0,
      lowStockAlertLimit: 5
    });
    setIsModalOpen(true);
  };

  const openEditModal = (item: Item) => {
    setEditingItem(item);
    reset(item);
    setIsModalOpen(true);
  };

  const onSubmit = async (data: Omit<Item, 'id' | 'currentStock'>) => {
    try {
      if (editingItem) {
        await updateItem(editingItem.id, data);
      } else {
        await addItem(data);
      }
      setIsModalOpen(false);
    } catch (error) {
      console.error("Error saving item:", error);
      alert("Failed to save item.");
    }
  };

  const handleDelete = async (id: string, name: string) => {
    if (confirm(`Are you sure you want to delete ${name}?`)) {
      await deleteItem(id);
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-slate-900">Inventory</h1>
          <p className="text-sm text-slate-500">Manage your products, services, and stock levels.</p>
        </div>
        <button 
          onClick={openAddModal}
          className="flex items-center gap-2 bg-blue-600 text-white px-4 py-2 rounded-md hover:bg-blue-700 transition"
        >
          <Plus className="h-4 w-4" /> Add Item
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-200 flex items-center gap-4">
          <div className="relative flex-1 max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 h-4 w-4" />
            <input 
              type="text" 
              placeholder="Search by product/service name..." 
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-9 pr-4 py-2 border border-slate-300 rounded-md text-sm focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>

        {isLoading ? (
          <div className="p-8 text-center text-slate-500">Loading inventory...</div>
        ) : filteredItems.length === 0 ? (
          <div className="p-12 text-center text-slate-500">
            <p>No inventory items found.</p>
            <button onClick={openAddModal} className="text-blue-600 font-medium hover:underline mt-2">
              Add your first product or service
            </button>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm whitespace-nowrap">
              <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
                <tr>
                  <th className="px-6 py-3">Item Name</th>
                  <th className="px-6 py-3">Type</th>
                  <th className="px-6 py-3 text-right">Sale Price</th>
                  <th className="px-6 py-3 text-right">Purchase Price</th>
                  <th className="px-6 py-3 text-right">Current Stock</th>
                  <th className="px-6 py-3 text-right">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-slate-200">
                {filteredItems.map((item) => (
                  <tr key={item.id} className="hover:bg-slate-50 transition">
                    <td className="px-6 py-4 font-medium text-slate-900">
                      {item.name}
                      <span className="block text-xs font-normal text-slate-500 mt-1">GST: {item.taxRate}%</span>
                    </td>
                    <td className="px-6 py-4">
                      <span className={`inline-flex items-center px-2 py-1 rounded-full text-xs font-medium capitalize ${item.type === 'product' ? 'bg-indigo-100 text-indigo-700' : 'bg-purple-100 text-purple-700'}`}>
                        {item.type}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      ₹{item.salePrice.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 text-right">
                      ₹{item.purchasePrice.toFixed(2)}
                    </td>
                    <td className="px-6 py-4 text-right">
                      {item.type === 'service' ? (
                        <span className="text-slate-400">-</span>
                      ) : (
                        <div className="flex items-center justify-end gap-2" title={item.currentStock <= item.lowStockAlertLimit ? "Low Stock" : ""}>
                          {item.currentStock <= item.lowStockAlertLimit && (
                            <AlertTriangle className="h-4 w-4 text-amber-500" />
                          )}
                          <span className={`font-medium ${item.currentStock <= 0 ? 'text-red-600' : 'text-slate-900'}`}>
                            {item.currentStock} {item.unit}
                          </span>
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button onClick={() => openEditModal(item)} className="text-blue-600 hover:text-blue-800 p-1">
                        <Edit className="h-4 w-4" />
                      </button>
                      <button onClick={() => handleDelete(item.id, item.name)} className="text-red-600 hover:text-red-800 p-1 ml-2">
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm p-4">
          <div className="bg-white rounded-xl shadow-xl w-full max-w-2xl overflow-hidden max-h-[90vh] flex flex-col">
            <div className="px-6 py-4 border-b border-slate-200 flex justify-between items-center bg-slate-50">
              <h2 className="text-lg font-semibold">{editingItem ? 'Edit Item' : 'Add New Item'}</h2>
              <button onClick={() => setIsModalOpen(false)} className="text-slate-400 hover:text-slate-700">
                <X className="h-5 w-5" />
              </button>
            </div>
            
            <div className="p-6 overflow-y-auto">
              <form id="item-form" onSubmit={handleSubmit(onSubmit)} className="space-y-6">
                
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-sm font-medium text-slate-700 text-red-600">Item Type *</label>
                    <div className="flex bg-slate-100 p-1 rounded-md">
                      <label className={`flex-1 text-center py-2 text-sm font-medium rounded cursor-pointer transition ${itemType === 'product' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}>
                        <input type="radio" value="product" {...register("type")} className="sr-only" />
                        Product
                      </label>
                      <label className={`flex-1 text-center py-2 text-sm font-medium rounded cursor-pointer transition ${itemType === 'service' ? 'bg-white shadow-sm text-blue-600' : 'text-slate-500 hover:text-slate-700'}`}>
                        <input type="radio" value="service" {...register("type")} className="sr-only" />
                        Service
                      </label>
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium text-slate-700 text-red-600">Item Name *</label>
                    <input 
                      {...register("name", { required: true })}
                      placeholder="e.g. Dell Monitor 24 inch"
                      className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    />
                  </div>
                  
                  <div className="space-y-2 md:col-span-2">
                    <label className="text-sm font-medium text-slate-700">Description</label>
                    <textarea 
                      {...register("description")}
                      rows={2}
                      className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 resize-none"
                    />
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium text-slate-700">Unit</label>
                    <select 
                      {...register("unit")}
                      className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      <option value="PCS">Pieces (PCS)</option>
                      <option value="KG">Kilograms (KG)</option>
                      <option value="LTR">Liters (LTR)</option>
                      <option value="BOX">Boxes (BOX)</option>
                      <option value="MTR">Meters (MTR)</option>
                      <option value="HRS">Hours (HRS)</option>
                    </select>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium text-slate-700">Tax Rate (GST %)</label>
                    <select 
                      {...register("taxRate", { valueAsNumber: true })}
                      className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                    >
                      <option value={0}>Exempt (0%)</option>
                      <option value={5}>5%</option>
                      <option value={12}>12%</option>
                      <option value={18}>18%</option>
                      <option value={28}>28%</option>
                    </select>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium text-slate-700 text-red-600">Sale Price *</label>
                    <div className="relative">
                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">₹</span>
                      <input 
                        type="number"
                        step="0.01"
                        {...register("salePrice", { required: true, valueAsNumber: true })}
                        placeholder="0.00"
                        className="w-full pl-8 pr-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                      />
                    </div>
                  </div>

                  <div className="space-y-2">
                    <label className="text-sm font-medium text-slate-700 text-red-600">Purchase Price *</label>
                    <div className="relative">
                      <span className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-500">₹</span>
                      <input 
                        type="number"
                        step="0.01"
                        {...register("purchasePrice", { required: true, valueAsNumber: true })}
                        placeholder="0.00"
                        className="w-full pl-8 pr-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                      />
                    </div>
                  </div>

                  {itemType === 'product' && (
                    <>
                      <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-700">Opening Stock</label>
                        <input 
                          type="number"
                          {...register("openingStock", { valueAsNumber: true })}
                          placeholder="0"
                          disabled={!!editingItem} // typically you don't edit opening stock directly later
                          className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500 disabled:bg-slate-50 disabled:text-slate-500"
                        />
                      </div>

                      <div className="space-y-2">
                        <label className="text-sm font-medium text-slate-700">Low Stock Alert Limit</label>
                        <input 
                          type="number"
                          {...register("lowStockAlertLimit", { valueAsNumber: true })}
                          placeholder="5"
                          className="w-full px-3 py-2 border border-slate-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
                        />
                      </div>
                    </>
                  )}
                </div>

              </form>
            </div>
            
            <div className="px-6 py-4 border-t border-slate-200 bg-slate-50 flex justify-end gap-3">
              <button 
                type="button" 
                onClick={() => setIsModalOpen(false)}
                className="px-4 py-2 text-sm font-medium text-slate-700 bg-white border border-slate-300 rounded-md hover:bg-slate-50"
              >
                Cancel
              </button>
              <button 
                type="submit" 
                form="item-form"
                className="px-4 py-2 text-sm font-medium text-white bg-blue-600 rounded-md hover:bg-blue-700"
              >
                Save Item
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

